local httpc = require "resty.http"
local ipmatcher = require "resty.ipmatcher"

-- Allowlist of allowed destination IPs/CIDRs
local allowlist = ipmatcher.new({
    "192.0.2.0/24",
    "203.0.113.0/24",
    -- Add more CIDRs as needed
})

-- Function to check if an IP is in the allowlist
local function is_allowed(ip)
    return allowlist:match(ip) ~= nil
end

-- Function to handle the request
local function handle_request()
    local url = ngx.var.arg_url
    if not url then
        ngx.status = 400
        ngx.say("Missing URL parameter")
        return
    end

    -- Extract IP from URL
    local ip = url:match("^https?://([^/]+)")
    if not ip then
        ngx.status = 400
        ngx.say("Invalid URL format")
        return
    end

    -- Check if the IP is allowed
    if not is_allowed(ip) then
        ngx.status = 403
        ngx.say("Access denied")
        return
    end

    -- Create HTTP client
    local httpc = httpc.new()

    -- Set timeout options
    httpc:set_timeout(5000)

    -- Make the request
    local res, err = httpc:request_uri(url)
    if not res then
        ngx.status = 500
        ngx.say("Failed to fetch URL: ", err)
        return
    end

    -- Handle redirects
    while res.status >= 300 and res.status < 400 do
        local location = res.headers["Location"]
        if not location then
            break
        end

        -- Extract IP from redirect URL
        ip = location:match("^https?://([^/]+)")
        if not ip then
            break
        end

        -- Check if the IP is allowed
        if not is_allowed(ip) then
            ngx.status = 403
            ngx.say("Access denied")
            return
        end

        -- Follow redirect
        res, err = httpc:request_uri(location)
        if not res then
            ngx.status = 500
            ngx.say("Failed to fetch URL: ", err)
            return
        end
    end

    -- Set response headers and body
    for k, v in pairs(res.headers) do
        ngx.header[k] = v
    end
    ngx.status = res.status
    ngx.say(res.body)
end

-- Call the request handler function
handle_request()